// Computes the folded result of a binary operation on two constant integers.
// Returns std::nullopt if the opcode is unsupported or the fold is unsafe
// (e.g. division by zero).
static std::optional<APInt> foldBinOp(unsigned Opcode, const APInt &LHS,
                                      const APInt &RHS) {
  switch (Opcode) {
  case Instruction::Add:
    return LHS + RHS;
  case Instruction::Sub:
    return LHS - RHS;
  case Instruction::Mul:
    return LHS * RHS;
  case Instruction::SDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.sdiv(RHS);
  case Instruction::UDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.udiv(RHS);
  case Instruction::Shl:
    return LHS.shl(RHS);
  case Instruction::LShr:
    return LHS.lshr(RHS);
  case Instruction::AShr:
    return LHS.ashr(RHS);
  case Instruction::And:
    return LHS & RHS;
  case Instruction::Or:
    return LHS | RHS;
  case Instruction::Xor:
    return LHS ^ RHS;
  default:
    return std::nullopt;
  }
}

bool myConstantPropagation(Function &Foo) {
  if (Foo.isDeclaration() || Foo.empty())
    return false;

  bool Changed = false;
  bool KeepGoing = true;

  // Iterate to a fixpoint: folding one instruction can turn a use of its
  // result into a new pair of constant operands (e.g. shl -> constant, then
  // sdiv of that constant).
  while (KeepGoing) {
    KeepGoing = false;

    for (BasicBlock &BB : Foo) {
      for (Instruction &I : make_early_inc_range(BB)) {
        auto *BinOp = dyn_cast<BinaryOperator>(&I);
        if (!BinOp)
          continue;

        auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
        auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
        if (!LHS || !RHS)
          continue;

        std::optional<APInt> Result =
            foldBinOp(BinOp->getOpcode(), LHS->getValue(), RHS->getValue());
        if (!Result)
          continue;

        Constant *Folded = ConstantInt::get(BinOp->getType(), *Result);
        BinOp->replaceAllUsesWith(Folded);
        BinOp->eraseFromParent();

        Changed = true;
        KeepGoing = true;
      }
    }
  }

  return Changed;
}

